869: /*
870:  * The client has sent a cancel request packet, not a normal
871:  * start-a-new-connection packet.  Perform the necessary processing.  Nothing
872:  * is sent back to the client.
873:  */
874: static void
875: ProcessCancelRequestPacket(Port *port, void *pkt, int pktlen)
876: {
877: 	CancelRequestPacket *canc;
878: 	int			len;
879: 
880: 	if (pktlen < offsetof(CancelRequestPacket, cancelAuthCode))
881: 	{
882: 		ereport(COMMERROR,
883: 				(errcode(ERRCODE_PROTOCOL_VIOLATION),
884: 				 errmsg("invalid length of cancel request packet")));
885: 		return;
886: 	}
887: 	len = pktlen - offsetof(CancelRequestPacket, cancelAuthCode);
888: 	if (len == 0 || len > 256)
889: 	{
890: 		ereport(COMMERROR,
891: 				(errcode(ERRCODE_PROTOCOL_VIOLATION),
892: 				 errmsg("invalid length of cancel key in cancel request packet")));
893: 		return;
894: 	}
895: 
896: 	canc = (CancelRequestPacket *) pkt;
897: 	SendCancelRequest(pg_ntoh32(canc->backendPID), canc->cancelAuthCode, len);
898: }
