779: /*----------------------------------------------------------------
780:  * Password-based authentication mechanisms
781:  *----------------------------------------------------------------
782:  */
783: 
784: /*
785:  * Plaintext password authentication.
786:  */
787: static int
788: CheckPasswordAuth(Port *port, const char **logdetail)
789: {
790: 	char	   *passwd;
791: 	int			result;
792: 	char	   *shadow_pass;
793: 
794: 	sendAuthRequest(port, AUTH_REQ_PASSWORD, NULL, 0);
795: 
